
import arabic_reshaper
from bidi.algorithm import get_display
from reportlab.lib.pagesizes import A4
from reportlab.lib.styles import ParagraphStyle
from reportlab.lib.units import mm
from reportlab.lib import colors
from reportlab.platypus import SimpleDocTemplate, Paragraph, Spacer, HRFlowable, PageBreak
from reportlab.pdfbase import pdfmetrics
from reportlab.pdfbase.ttfonts import TTFont
from reportlab.lib.enums import TA_RIGHT, TA_CENTER, TA_LEFT

# Register Arabic fonts
pdfmetrics.registerFont(TTFont('NotoArabic', '/usr/share/fonts/truetype/noto/NotoSansArabic-Regular.ttf'))
pdfmetrics.registerFont(TTFont('NotoArabicBold', '/usr/share/fonts/truetype/noto/NotoSansArabic-Bold.ttf'))

def ar(text):
    """Reshape and reorder Arabic text for correct PDF rendering."""
    reshaped = arabic_reshaper.reshape(text)
    return get_display(reshaped)

# ─────────────────────────────────────────────
# STYLES
# ─────────────────────────────────────────────
def make_styles():
    cover_title = ParagraphStyle(
        'CoverTitle', fontName='NotoArabicBold', fontSize=26,
        leading=38, alignment=TA_CENTER, textColor=colors.HexColor('#FFD700'),
        spaceAfter=6
    )
    cover_sub = ParagraphStyle(
        'CoverSub', fontName='NotoArabic', fontSize=13,
        leading=20, alignment=TA_CENTER, textColor=colors.HexColor('#AAAAAA'),
        spaceAfter=4
    )
    act_title = ParagraphStyle(
        'ActTitle', fontName='NotoArabicBold', fontSize=20,
        leading=30, alignment=TA_RIGHT, textColor=colors.HexColor('#FF4500'),
        spaceBefore=14, spaceAfter=8
    )
    scene = ParagraphStyle(
        'Scene', fontName='NotoArabicBold', fontSize=11,
        leading=17, alignment=TA_CENTER, textColor=colors.HexColor('#00BFFF'),
        spaceBefore=8, spaceAfter=4,
        borderPad=4
    )
    sfx = ParagraphStyle(
        'SFX', fontName='NotoArabic', fontSize=10,
        leading=15, alignment=TA_CENTER, textColor=colors.HexColor('#888888'),
        spaceBefore=4, spaceAfter=4, italics=1
    )
    mazag = ParagraphStyle(
        'Mazag', fontName='NotoArabicBold', fontSize=12,
        leading=19, alignment=TA_RIGHT, textColor=colors.HexColor('#FFD700'),
        spaceBefore=7, spaceAfter=2, leftIndent=10, rightIndent=0
    )
    solo = ParagraphStyle(
        'Solo', fontName='NotoArabicBold', fontSize=12,
        leading=19, alignment=TA_RIGHT, textColor=colors.HexColor('#00FF99'),
        spaceBefore=7, spaceAfter=2, leftIndent=10, rightIndent=0
    )
    body_r = ParagraphStyle(
        'BodyR', fontName='NotoArabic', fontSize=12,
        leading=20, alignment=TA_RIGHT, textColor=colors.HexColor('#E8E8E8'),
        spaceBefore=0, spaceAfter=4, rightIndent=0, leftIndent=10
    )
    section_head = ParagraphStyle(
        'SectionHead', fontName='NotoArabicBold', fontSize=14,
        leading=22, alignment=TA_RIGHT, textColor=colors.HexColor('#FF8C00'),
        spaceBefore=12, spaceAfter=6
    )
    time_stamp = ParagraphStyle(
        'TimeStamp', fontName='NotoArabic', fontSize=9,
        leading=14, alignment=TA_CENTER, textColor=colors.HexColor('#555555'),
        spaceBefore=2, spaceAfter=2
    )
    return dict(
        cover_title=cover_title, cover_sub=cover_sub,
        act_title=act_title, scene=scene, sfx=sfx,
        mazag=mazag, solo=solo, body_r=body_r,
        section_head=section_head, time_stamp=time_stamp
    )

# ─────────────────────────────────────────────
# HELPERS
# ─────────────────────────────────────────────
def M(text, styles):
    return [
        Paragraph(ar('[مزاج]:'), styles['mazag']),
        Paragraph(ar(text), styles['body_r'])
    ]

def S(text, styles):
    return [
        Paragraph(ar('[سولو]:'), styles['solo']),
        Paragraph(ar(text), styles['body_r'])
    ]

def SFX(text, styles):
    return Paragraph(ar(f'[SFX: {text}]'), styles['sfx'])

def T(text, styles):
    return Paragraph(ar(text), styles['time_stamp'])

def ACT(text, styles):
    return Paragraph(ar(text), styles['act_title'])

def SEC(text, styles):
    return Paragraph(ar(text), styles['section_head'])

def HR():
    return HRFlowable(width='100%', thickness=0.5,
                      color=colors.HexColor('#333333'), spaceAfter=6, spaceBefore=6)

def add(*items, story):
    for item in items:
        if isinstance(item, list):
            story.extend(item)
        else:
            story.append(item)

# ─────────────────────────────────────────────
# BUILD STORY
# ─────────────────────────────────────────────
def build_story(styles):
    story = []

    # ══════════════════════════════════════════
    # COVER PAGE
    # ══════════════════════════════════════════
    story.append(Spacer(1, 30*mm))
    story.append(Paragraph(ar('🎙️ بودكاست'), styles['cover_sub']))
    story.append(Spacer(1, 5*mm))
    story.append(Paragraph(ar('من المكنة للهيدفون'), styles['cover_title']))
    story.append(Paragraph(ar('رحلة العفرتة'), styles['cover_title']))
    story.append(Spacer(1, 8*mm))
    story.append(Paragraph(ar('— سكريبت كامل — مدة: ساعتين —'), styles['cover_sub']))
    story.append(Spacer(1, 6*mm))
    story.append(Paragraph(ar('المذيعان: مزاج & سولو'), styles['cover_sub']))
    story.append(Spacer(1, 4*mm))
    story.append(Paragraph(ar('النوع: ستريت-سمارت | هاستل | موسيقى | ثقافة الشارع المصري'), styles['cover_sub']))
    story.append(Spacer(1, 30*mm))
    story.append(HR())
    story.append(Paragraph(ar('الفهرس'), styles['section_head']))
    story.append(Paragraph(ar('الفصل الأول: استراتيجية الثانوية العامة — ٤٥ دقيقة'), styles['body_r']))
    story.append(Paragraph(ar('الفصل الثاني: الهاوجينج Z250 وجرايند تعليبات — ٣٠ دقيقة'), styles['body_r']))
    story.append(Paragraph(ar('الفصل الثالث: الخطة المالية — جير ضد الواقع — ٣٠ دقيقة'), styles['body_r']))
    story.append(Paragraph(ar('الفصل الرابع: فيجن ييت / يونغ جيزة — ١٥ دقيقة'), styles['body_r']))
    story.append(PageBreak())

    # ══════════════════════════════════════════
    # ACT 1
    # ══════════════════════════════════════════
    add(ACT('═══ الفصل الأول ═══', styles), story=story)
    add(ACT('استراتيجية الثانوية العامة: تحسين الدماغ', styles), story=story)
    add(T('[ الوقت: 00:00 — 00:45 ]', styles), story=story)
    add(HR(), story=story)
    add(SFX('صوت موتوسيكل بيشتغل في الصبح بدري — ضوضاء شارع مصري — بوق تاكسي — بعدين بيهدى على بيت ترابي داكن وبيانو', styles), story=story)
    add(Spacer(1, 4*mm), story=story)

    add(SEC('— المقدمة والتعريف —', styles), story=story)

    add(*M('أيه الدنيا يا ناس! أنا مزاج، وده بودكاست "من المكنة للهيدفون: رحلة العفرتة". الجلسة دي مش جلسة عادية يا زميلي — احنا هنتكلم عن كل حاجة. الثانوية، المكنة، الفلوس، الاستوديو، والميوزيك. كله في بعض زي الكشري بالصلصة الحارة!', styles), story=story)
    add(*S('وأنا سولو يا عيال! والله يا مزاج إنت اخترت الوصف الصح — كشري بالصلصة الحارة! ده احنا بالظبط. الكلام اللي هنقوله النهارده ممكن يغير حياتك لو عندك عقل وعندك قلب وعندك إرادة. بس لو إنت جاي تسمع وتتفرج وبعدين ترجع تنام، يبقى فكك منا من دلوقتي!', styles), story=story)
    add(*M('بالظبط! إحنا بنتكلم للواحد اللي بيصحى الصبح وعنده حلم بس مش عارف يوصله. اللي شايف الدنيا ضيقة عليه بس هو نفسه مش عارف يوسعها. اللي بيشتغل بالليل ومش عارف يذاكر بالنهار. اللي بيفكر في الموسيقى وأهله بيقوله "ادرس يا بني"!', styles), story=story)
    add(*S('آه، ده اللي بنتكلمه. وأنا عارف الكلام ده مش من الكتب — ده من الشارع. من الدايري، من شارع فيصل، من عمارات عشوائية في أي حتة في مصر. من واحد زيك وزيي اتعلم بالجلد.', styles), story=story)
    add(*M('طب خلينا نبدأ من أول حاجة وأكتر حاجة بتاخد بال الواحد في مصر — الثانوية العامة. يا ريت حد يفهمنا ليه الثانوية العامة بالظبط بتحسسك إنها نهاية الدنيا؟', styles), story=story)
    add(*S('عارفك ليه يا مزاج؟ لأن كل الناس حواليك عملوها كده. أمك، أبوك، خالتك سعاد، جارك أبو شبكسة، كلهم بيقولوا "الثانوية هي اللي بتحدد مستقبلك كله!". وإنت صغير تصدق الكلام ده وتحس إن مفيش تاني.', styles), story=story)
    add(*M('وأنا مش رافض الثانوية خالص — لأ! الثانوية مهمة. بس الطريقة اللي الناس بتتعامل بيها مع الثانوية دي بتخلي الواحد يفشل فيها قبل ما يبدأ. خوف قبل الامتحان بشهور. ضغط نفسي. الواحد بيدخل الامتحان وهو زي ما حد حاطط عياله على رأسه.', styles), story=story)
    add(Spacer(1, 3*mm), story=story)
    add(HR(), story=story)
    add(SEC('— تحسين الدماغ: إزاي تذاكر ١٠ ساعات من غير ما تحرق —', styles), story=story)
    add(SFX('موسيقى ترابي هادية في الخلفية — تيكنو لو فاي', styles), story=story)

    add(*S('طب سولو، خليني أسألك سؤال مباشر. إنت فاكر امتى كنت بتذاكر؟ كنت بتعمل إيه بالظبط؟', styles), story=story)
    add(*M('يا سيدي، أنا كنت واحد من اللي بيقولوا "هذاكر ١٠ ساعات" وبعدين بعد ساعة بتلاقيني بأتفرج على تيك توك. وده مش لأني كسلان — ده لأن طريقتي في المذاكرة كانت غلط من الأساس. كنت باجلس على الكتاب وأحاول أحفظ. حفظ جاف، من غير فهم، من غير هيكل.', styles), story=story)
    add(*S('وده بالظبط اللي بيعمله ٩٠٪ من طلاب الثانوية في مصر. جلوس طويل، نتيجة صفر. وبعدين بيقولوا "أنا مش ذكي". لأ يا صديقي، إنت ذكي — إنت بس مش عارف تشتغل صح.', styles), story=story)
    add(*M('طب خليني أشرح التيكنيك اللي لقيته بعد ما فشلت مرتين واتعلمت. الأول — مبدأ الـ Pomodoro بس بطريقة عفرتة مصرية. مش ٢٥ دقيقة زي ما بيقولوا في اليوتيوب. ده للناس اللي عندهم مكيف ومحتاج قهوة ستاربكس. احنا بنعمل ٤٥ دقيقة تركيز حقيقي، ١٥ دقيقة راحة حقيقية.', styles), story=story)
    add(*S('وفي الـ ٤٥ دقيقة دول، الموبايل بعيد. مش سايلنت — بعيد. في أوضة تانية لو عندك أوضة. في الدرج لو معندكش. الناس بتفتكر إن السايلنت كافي، بس مجرد ما الموبايل قدامك ودماغك بيفكر فيه حتى لو مبيرنش.', styles), story=story)
    add(*M('ده عندنا بيتسمى "الإغراء البصري". الدراسات بتقول إن مجرد شوفتك للموبايل بتخفض IQ الجلسة بتاعتك بـ ١٠ نقط. عشر نقط! يعني أنت قاعد تذاكر وأنت أغبى من الطبيعي لأن الموبايل في جيبك!', styles), story=story)
    add(*S('ده كلام مش بنختلقه يا مزاج — ده research من University of Texas. بس النقطة المهمة هنا إن احنا كمصريين عندنا تحدي إضافي — البيت. البيت المصري مش مصمم للمذاكرة.', styles), story=story)
    add(*M('آه ربنا يستر! إنت بتذاكر وأمك بتزعق "الغدا جاهز!". أختك بتذاكر هي برضو وفي ضغط. التلفزيون شغال في الأوضة الصالة. الجيران بيعملوا دوشة. وإنت المفروض تركز على قوانين نيوتن!', styles), story=story)
    add(*S('بالظبط! وده اللي خليني أقول إن الثانوية مش امتحان في الفيزيا والرياضة بس — ده امتحان في الـ Mental Strength. إنت بتتحان على قدرتك إنك تركز وسط الفوضى. وده مهارة نفسها لازم تتدرب عليها.', styles), story=story)
    add(*M('طب إزاي؟ خليني أقولك التيكنيك اللي اتعلمته. أول حاجة — الـ Environment Design. يعني صمم بيئتك قبل ما تذاكر. مش لازم تشتري حاجة. كرسي وطاولة ومكان واحد في البيت هو مكان المذاكرة بس. مش السرير. السرير هو عدو الطالب.', styles), story=story)
    add(*S('آه! السرير دي مصيدة! بتقول "هذاكر على السرير" وبعد ١٠ دقيقة بتصحى وإنت مش عارف الساعة كام. الجسم اتعلم إن السرير = نوم، فأي وقت إنت فوقيه دماغك بيدخل في وضع النوم أوتوماتيك.', styles), story=story)
    add(*M('تاني حاجة — الـ Noise Canceling بطريقة بلدي. لو معندكش هيدفون بـ ANC، اللي هو ده في أجندتنا إننا نشتريه، في حل تاني. وايت نويز من يوتيوب — صوت مطر، صوت مروحة، صوت هواء. ده بيخدع دماغك ويخليه مش حاسس بالأصوات المتقطعة.', styles), story=story)
    add(*S('وأنا باضيف تيكنيك آخر اتعلمته — الـ Anchor Music. يعني موسيقى إنت بتشغلها بس وقت المذاكرة. مش أغاني فيها كلام. موسيقى إنسترومنتال. بعد أسبوعين، دماغك هيتعلم إن لما الموسيقى دي بتشتغل، يعني وقت شغل.', styles), story=story)
    add(*M('كلام جميل وده بالظبط حاجة الـ Pavlovian Conditioning — زي ما الكلب بتاع بافلوف اتعلم يبصق لما بيسمع الجرس، إنت بتعلم دماغك يدخل في وضع المذاكرة لما الموسيقى دي بتشتغل. وده شغال مع الترابي برضو بالمناسبة!', styles), story=story)
    add(*S('ووووه! كنت هقول ده! الترابي الإنسترومنتال ده بيعمل حاجة في دماغي مش بيعملها أي حاجة تانية. ولو بتحاول تبني استوديو في المستقبل يبقى إنت بتتعلم إنك تسمع الموسيقى من ناحية تقنية وده بيطور أذنك.', styles), story=story)
    add(Spacer(1, 3*mm), story=story)
    add(SEC('— تيكنيكات للفيزيا والرياضة تحديداً —', styles), story=story)
    add(SFX('قلم بيكتب على ورق — صوت حاسبة — نبضات موسيقى', styles), story=story)

    add(*M('طب، نتكلم عن الفيزيا والرياضة تحديداً لأن دول المواد اللي بتخوف الناس أكتر. ومعظم الناس بتفشل فيهم مش لأنهم صعبين — لأن الناس بتحاول تحفظهم زي الأدب والتاريخ.', styles), story=story)
    add(*S('ده الغلطة الأم! الفيزيا والرياضة مش بتتحفظ — بتتفهم. ولو فهمتهم فهم حقيقي، مش محتاج تحفظ إلا حاجات قليلة جداً. القوانين الأساسية، الوحدات، والعلاقات. باقي كل حاجة بتيجي من الفهم.', styles), story=story)
    add(*M('وأنا هشرح الطريقة اللي اتعلمتها لما قررت إني أفهم بدل ما أحفظ. في الفيزيا، كل موضوع له سؤال واحد مركزي. مثلاً في الحركة — السؤال المركزي هو "إيه اللي بيخلي حاجة تتحرك أو توقف؟". لو فهمت الإجابة دي فهم حقيقي، كل المسائل بتبقى تطبيقات على نفس الفكرة.', styles), story=story)
    add(*S('وفي الرياضة — كل فصل عنده فكرة جوهرية واحدة. في حساب المثلثات — الفكرة هي العلاقة بين الزوايا والأضلاع. في الإحصاء — الفكرة هي إزاي تلخص بيانات كتير في أرقام بسيطة. لو حفظت الفكرة الجوهرية دي وفهمتها، المسائل هتبقى سهلة.', styles), story=story)
    add(*M('والتيكنيك العملي اللي بنسميه "اشرح للحيطة". وده مش نكتة. إنت قاعد لوحدك في أوضتك، وبتشرح الموضوع لحيطة فاضية. أو لعروسة. أو لقطتك. المهم إنك بتشرح بالكلام. لو لقيت نفسك وقفت، يبقى في حاجة مش فاهمها صح.', styles), story=story)
    add(*S('ده اللي العلم بيسميه "Feynman Technique". سميه زي ما تحب. بس الجوهر هو إنك لو قدرت تشرح الحاجة بكلام بسيط لواحد معندوش أي معرفة، يبقى إنت فاهمها. ولو ما قدرتش، يبقى فهمك ناقص.', styles), story=story)
    add(*M('وفي الفيزيا تحديداً، في تيكنيك أنا بسميه "الرسمة الأم". قبل أي مسألة — ارسم. ارسم الموقف. ارسم الأجسام. ارسم الاتجاهات. ٨٠٪ من وقت طالب الفيزيا بيضيع لأنه مش شايف الصورة في دماغه.', styles), story=story)
    add(*S('وبعدين في موضوع المراجعة. المراجعة الغلط بتضيع وقتك وبتخليك تحس بالأمان الزيف. إنت قاعد تقرأ الكتاب مرة تانية — ده مش مراجعة. ده إعادة قراءة. المراجعة الحقيقية إنك تقفل الكتاب وتجاوب على أسئلة. إنك تحل مسائل من غير ما تبص على الحل.', styles), story=story)
    add(*M('وإنت بتحل المسائل — مهم جداً إنك تحل من امتحانات السنين اللي فاتت. دي أهم أداة عندك. ومش بس تحل — تحل بـ Timing. اعمل مؤقت. الامتحان الحقيقي هيبقى في وقت ضغط، وإنت لازم تتعلم تشتغل مضغوط.', styles), story=story)
    add(Spacer(1, 3*mm), story=story)
    add(SEC('— القوة الذهنية: إزاي تتجاهل الضغط —', styles), story=story)
    add(SFX('صوت ناس بتتكلم في الخلفية — بعدين بيهدى — نبض باس لاين', styles), story=story)

    add(*S('طب، نتكلم عن الجزء اللي ما حدش بيتكلم عنه كفاية — الضغط النفسي. الضغط من الأهل، من المجتمع، من الـ "هتعمل إيه في حياتك؟"', styles), story=story)
    add(*M('آه! الضغط النفسي ده في رأيي هو السبب الأول في فشل طلاب الثانوية — مش الصعوبة الأكاديمية. واحد بيذاكر تمام، بس كل أسبوع عمته بتيجي البيت وبتسأل "طلعت إيه في المراجعة؟" أو "إبن جارتنا فلان طلع كذا في التجريبي". وده بيدمر المعنويات.', styles), story=story)
    add(*S('وأنا بسميه "الضغط الجانبي". مش الضغط من فوق — ده من الجانب. من الناس حواليك. والمشكلة إن الناس دي مش بتقصد تأذيك — هم بيعبروا عن قلقهم بطريقة غلط.', styles), story=story)
    add(*M('بس دي مشكلتهم مش مشكلتك. وهنا بييجي مبدأ "شوف مصلحتك". وده مش معناه تبقى أناني أو ماتسمعش أهلك. معناه إنك تعرف ما هو الهدف الحقيقي وتشتغل عليه من غير ما تتأثر بالضوضاء الجانبية.', styles), story=story)
    add(*S('وعندي مثال عملي. لما حد بيقولك "إبن فلان عمل كذا"، الإجابة الصح مش إنك تتضايق أو تتدافع. الإجابة الصح هي إنك تقول في دماغك "كويس ليه. أنا عندي خطة مختلفة وكل حاجة بتيجي في وقتها". وتمشي تذاكر.', styles), story=story)
    add(*M('وده محتاج تدريب. مش بيجي أوتوماتيك. محتاج إنك كل يوم تذكر نفسك بهدفك. وهنا بيجي دور الـ Journaling — الكتابة اليومية. كل يوم تكتب في دفتر: ما هو هدفي؟ ما اللي عملته النهارده عشانه؟ وما اللي لازم أعمله بكره؟', styles), story=story)
    add(*S('الكتابة دي بتعمل حاجتين: أولاً بتخليك تشوف تقدمك فعلياً ومش بس حاسس بيه. وتانياً بتخليك مسؤول قدام نفسك. لو كتبت إنك هتذاكر ٥ ساعات ومذاكرتش، الصفحة التانية هيبقى فيها السؤال "ليه؟".', styles), story=story)
    add(*M('وموضوع العلاقة مع الأهل — وأنا هنا بكلم صراحة. الأهل في معظمهم عايزين خيرك. بس طريقة تعبيرهم عن ده في أحيان كتير بتكون ضارة. المطلوب منك مش إنك تتجاهلهم — المطلوب إنك تعمل محادثة واضحة معاهم.', styles), story=story)
    add(*S('قولهم: "أنا عارف إنكم خايفين عليا وده بيحسسني بالحب. بس لما بتقولوا لي كل يوم إني هفشل، ده بيأثر في تركيزي وبيوصلني الموضوع عكسي. أنا محتاج ثقتكم مش ضغطكم." الكلام ده لو قلته بهدوء وباحترام، معظم الأهل بيفهموه.', styles), story=story)
    add(*M('والنقطة دي مهمة جداً — مش بس للثانوية. ده مبدأ حياتي. إنك تتكلم صح، وتشرح ما تحتاجه، وتطلب الدعم بدل ما تحارب الضغط بالانسحاب والصمت.', styles), story=story)
    add(Spacer(1, 3*mm), story=story)
    add(SEC('— جدول المذاكرة الأمثل: ١٠ ساعات من غير ما تحرق —', styles), story=story)
    add(SFX('تيك توك ساعة — صوت كتابة — نبضة موسيقى تيكنو بطيئة', styles), story=story)

    add(*S('طب، خليني أشرح جدول المذاكرة اللي اتعلمته وشغال معايا. مش جدول مثالي من كتاب — جدول من الواقع.', styles), story=story)
    add(*M('يلا، إحنا بنستنى!', styles), story=story)
    add(*S('الساعة ٦ الصبح: صحيان. مش لأني بوظة ومحبش النوم — لأن الصبح البكري هو أهدأ وقت في اليوم. قبل ما الدنيا تصحى. وعقلك بعد النوم بيكون في أعلى مستوى تركيز.', styles), story=story)
    add(*M('وفي ٦ الصبح في مصر في الشتا، الجو تمام والهواء نضيف نسبياً. وفي الصيف، ده أبرد وقت قبل الحر الجنان.', styles), story=story)
    add(*S('من ٦ لـ ٦:٣٠ — روتين الصبح. مش إيه ده؟ تصحى، تغسل وشك، تاكل حاجة خفيفة — موز أو بيضة أو أي حاجة. وتتحرك جسمك ٥ دقايق. مش جيم كامل — خطوات في الأوضة. الهدف تشغّل جسمك.', styles), story=story)
    add(*M('من ٦:٣٠ لـ ٧:٣٠ — أصعب مادة عندك. وقت الصبح ده للمادة اللي بتخوفك. الرياضة، الفيزيا، الكيميا. الدماغ في أفضل حالة، استخدمه فيما يستاهل.', styles), story=story)
    add(*S('من ٧:٣٠ لـ ٧:٤٥ — راحة. خروج برة أحسن لو ممكن. نظر لبعيد. إياك الموبايل في الراحة — ده بيخلي الراحة مش راحة.', styles), story=story)
    add(*M('من ٧:٤٥ لـ ٨:٤٥ — مادة تانية. ممكن أسهل شوية. الأدب، التاريخ، الجغرافيا. ليه بعد الأصعب؟ لأن الدماغ بعد ساعة شغل صعب بيحتاج تغيير، ومادة أسهل بتعمله راحة نسبية من غير ما تقعد فاضي.', styles), story=story)
    add(*S('من ٨:٤٥ لـ ٩ — فطار حقيقي. وهنا مهم جداً. الأكل مش مجرد بنزين للجسم — هو وقود للدماغ. دماغك بياكل جلوكوز. لو ما أكلتش كويس، تركيزك بينزل. بيضة وعيش وجبنة أحسن من شيبس.', styles), story=story)
    add(*M('من ٩ لـ ١٠:٣٠ — جلسة تالتة. مراجعة اللي اتعملت فيه الأيام اللي فاتت. Active Recall — مش قراءة. سؤال وجواب. Flashcards لو عندك أو عمّلتهم.', styles), story=story)
    add(*S('من ١٠:٣٠ لـ ١١ — وقت لقفشة. ده وقت حر حقيقي. موبايل، كلام مع صاحب، أي حاجة. الراحة الحقيقية دي ضرورية عشان تكمل.', styles), story=story)
    add(*M('من ١١ لـ ١٢:٣٠ — جلسة مسائل وتطبيقات. مش نظريات. مسائل فعلية من امتحانات سابقة. الفيزيا والرياضة بيتذاكروا بالحل مش بالقراءة.', styles), story=story)
    add(*S('من ١٢:٣٠ لـ ٢ — غدا وقيلولة. القيلولة دي ذهب. ٢٠-٣٠ دقيقة نوم بعد الغدا بتعمل Reboot للدماغ. بالظبط زي ما بتعمل ريستارت للكمبيوتر لما بيبطأ.', styles), story=story)
    add(*M('من ٢ لـ ٤ — الجلسة الكبيرة. دي أطول جلسة في اليوم. ممكن فيها مادة كاملة أو جزء كبير. بعد القيلولة الدماغ بيكون أفضل.', styles), story=story)
    add(*S('من ٤ لـ ٥ — راحة مع حركة. امشي نص ساعة في الشارع. ده مش وقت ضايع — ده وقت بيشتغل فيه دماغك على المعلومات اللي أخدتها من غير ما تحس. كتير من أفضل الأفكار بتيجي وإنت ماشي.', styles), story=story)
    add(*M('من ٥ لـ ٧ — جلسة مسائية. دي للمراجعة الخفيفة والتحضير لبكره. مش جلسة جديدة بالكامل — تثبيت لما اتعمل.', styles), story=story)
    add(*S('من ٧ لـ ٩ — وقت الأسرة والعشا. وده مهم إنك تفصل فيه المذاكرة خالص. ماكلش وكتاب في إيدك. الأسرة والراحة مهمين للصحة النفسية.', styles), story=story)
    add(*M('من ٩ لـ ١٠ — مراجعة أخيرة. قصيرة ومش مكثفة. مجرد قرا على ورقة ملاحظات قصيرة اللي عملتها في النهار. ده بيثبت المعلومات في الذاكرة طويلة المدى.', styles), story=story)
    add(*S('ومن ١٠ — نوم. مش جوال. مش يوتيوب. نوم. النوم ده اللي بيثبت كل اللي ذاكرته. لو مذاكرت ١٠ ساعات ونمت ٤، هتصحى ناسي نصهم. النوم هو الـ Save Button بتاع دماغك.', styles), story=story)
    add(*M('ومجموع الجدول ده تقريباً ٨-١٠ ساعات مذاكرة فعلية. مش جلوس — مذاكرة فعلية. مع راحة كافية ومع الحياة الطبيعية. ده الجدول اللي بيشتغل مع البشر العاديين في البيوت العادية في مصر.', styles), story=story)
    add(Spacer(1, 3*mm), story=story)
    add(SEC('— ما بعد الثانوية: الفيجن المهم —', styles), story=story)

    add(*S('وأنا عايز أختم الجزء ده بكلمة مهمة. الثانوية مهمة — بس مش نهاية الدنيا. لو عملت كويس، كويس. لو معملتش كويس، مش نهاية الدنيا. في ناس كتير في مصر والعالم كله عملوا حاجات عظيمة من غير ما يكون عندهم مجموع عالي.', styles), story=story)
    add(*M('بس الكلام ده مش مبرر لإنك تتكاسل. الكلام ده بيقول إن الطريق مش واحد. لو عملت كويس في الثانوية، هيفتحلك أبواب معينة. ولو اخترت طريق تاني — الشغل، الحرفة، الموسيقى، أي حاجة — فيه أبواب تانية. بس في كل الأحوال، لازم تديها جد.', styles), story=story)
    add(*S('وأنا هقولك سر — أكتر حاجة مفيدة في التجربة بتاعة الثانوية مش المعلومات نفسها. هي إنك بتتعلم إزاي تتعامل مع ضغط. إزاي تنظم وقتك. إزاي تشتغل وإنت خايف. دي skills بتاخدها معاك طول عمرك.', styles), story=story)
    add(*M('وده اللي بيربط الثانوية بالجزء التاني من بودكاستنا — لأن اللي بيجي بعدين هو الشغل الحقيقي. واللي اتعلمته في الثانوية هو نفس اللي هتحتاجه لما تكون على المكنة في الدايري الساعة ١١ بالليل وعندك ٢٠ أوردر لازم تسلمهم!', styles), story=story)
    add(SFX('موسيقى ترانزيشن — صوت موتوسيكل يشتغل', styles), story=story)
    add(PageBreak(), story=story)

    # ══════════════════════════════════════════
    # ACT 2
    # ══════════════════════════════════════════
    add(ACT('═══ الفصل الثاني ═══', styles), story=story)
    add(ACT('الهاوجينج Z250 وجرايند تعليبات', styles), story=story)
    add(T('[ الوقت: 00:45 — 01:15 ]', styles), story=story)
    add(HR(), story=story)
    add(SFX('صوت موتوسيكل بيرفرف — ضوضاء مدينة — بوق عربيات — اهتزاز تليفون', styles), story=story)
    add(Spacer(1, 4*mm), story=story)

    add(SEC('— الهاوجينج Z250: ليه هي الحمالة الأسية —', styles), story=story)

    add(*M('يا ناس! خليني أوريكم كده، إيه الدنيا! بعد ما تكلمنا عن الثانوية، خليني أتكلم عن الحياة الحقيقية. الحياة اللي فيها الموتوسيكل والأوردر والدايري. إحنا في الفصل الثاني، وهنتكلم عن الهاوجينج Z250 — اللي هي في رأيي أكتر موتوسيكل مظلوم وفي نفس الوقت أكتر موتوسيكل بيتشغل في مصر.', styles), story=story)
    add(*S('الهاوجينج Z250! يا سيدي، الاسم ده لو قلته قدام ميكانيكي بيتبسم. لأنها واحدة من أكتر المكاين اللي شغالة في مصر وفي نفس الوقت واحدة من أقلهم اتكلم عنها بجد في الإنترنت العربي.', styles), story=story)
    add(*M('وأنا هشرح ليه هي "حمالة أسية" وده مش شتيمة — ده مدح في عالم التوصيل. "حمالة أسية" يعني قادرة تتحمل ضغط شغل حقيقي، كل يوم، من الصبح للعشا، من غير ما تشتكي كتير.', styles), story=story)
    add(*S('الـ Z250 دي موتور ٢٥٠cc، ١٥-١٧ حصان تقريباً حسب الموديل والسنة. مش سريعة زي الـ CBR أو ZX ولا متوقع منها كده. دي مش موتور سباق — دي موتور شغل. وفي الشغل، الموتور الكويس مش اللي بيوصل أسرع — اللي بيوصل أأمن وأوثق.', styles), story=story)
    add(*M('وفي مصر، الكلام ده مهم جداً. الطرق في مصر — وأنا بتكلم عن طرق المناطق اللي بنشتغل فيها — مش طرق ألمانيا. طرق فيها حفر، فيها مطبات مش معمولة صح، فيها زحمة، فيها مناورات غير متوقعة. محتاج موتور متوازن ومش هيبقى محتاج إصلاح كل أسبوع.', styles), story=story)
    add(*S('الـ Z250 في الشغل اليومي بتاكل ١ لـ ١.٥ لتر بنزين على ١٠٠ كيلو في المدينة. ده رقم كويس جداً للشغل في القاهرة حيث الزحمة والفرملة والتشغيل المستمر. قارن ده بموتور ٤٠٠cc أو ٦٠٠cc اللي ممكن ياكل ضعف ده في نفس الظروف.', styles), story=story)
    add(*M('والجسم بتاعها مناسب لحمل الشنط والأكياس. المقعد الخلفي المسطح والـ Grab Bars القوية بتخلي تثبيت الـ Delivery Bag سهل وثابت. مش كل موتور عنده ده.', styles), story=story)
    add(*S('وقطع الغيار — وده مهم جداً — متوفرة في مصر. الـ Z250 مستوردة بكميات كبيرة ومعمول لها Copy Parts محلية بأسعار معقولة. لو انكسرت حاجة مش هتضطر تستني أسبوعين لـ أوردر قطعة من الصين.', styles), story=story)
    add(Spacer(1, 3*mm), story=story)
    add(SEC('— الصيانة الذكية: الفلوس تفضل في جيبك —', styles), story=story)
    add(SFX('صوت ورشة — مفاتيح على حديد — صوت محرك', styles), story=story)

    add(*M('طب، نتكلم عن الجزء اللي الناس بتهمله وبيخسر منه فلوس كتير — الصيانة. الصيانة الغلط أو الإهمال في الصيانة هو أكبر حاجة بتأكل أرباحك في شغل التوصيل.', styles), story=story)
    add(*S('وأنا هقولك من تجربتي. أول ما بدأت في التوصيل، كنت مش باهتم بالصيانة كتير. بقول "الموتور شغال، ما فيش مشكلة". وبعدين يجي يوم وأنا في نص أوردر والموتور يبقى محتاج إصلاح كبير يكلف أكتر بكتير من لو كنت صانته بانتظام.', styles), story=story)
    add(*M('وده بالظبط اللي إحنا هنتكلم عنه. الصيانة مش مصاريف — الصيانة هي استثمار في مصدر رزقك. موتورك هو بيزنسك. لو البيزنس وقف، الفلوس وقفت.', styles), story=story)
    add(*S('أول حاجة — الزيت. في الـ Z250 المبدأ العام إنك تغير الزيت كل ٣٠٠٠ كيلو أو كل شهرين في الشغل الشديد. بس في مصر، في الزحمة والحر الجنان، أنا بنصح بكل ٢٠٠٠-٢٥٠٠ كيلو.', styles), story=story)
    add(*M('ليه؟ لأن الزحمة والتشغيل المتقطع في القاهرة بيضغط على الزيت أكتر من السفر على الطريق الدائري المفتوح. الزيت بيتأكسد أسرع. وزيت باظ يعني محرك باظ. ومحرك باظ يعني ألاف الجنيهات.', styles), story=story)
    add(*S('والزيت — خد باله من النوع. مش لازم الأغلى، بس مش الأرخص خالص. زيت نص معدني بـ 10W-40 مناسب للمناخ المصري. وهو بيتباع في مصر بأسعار معقولة. تقريباً ١٥٠-٢٥٠ جنيه للتر حسب الماركة. والـ Z250 بتاخد ١.٥ لـ ٢ لتر في كل تغيير. يعني تغيير الزيت بـ ٣٠٠-٥٠٠ جنيه مش أكتر.', styles), story=story)
    add(*M('وتغيير الزيت نفسك — ده ممكن تتعلمه وتوفر فلوس الورشة. المهارة دي سهلة وبتاخد ٢٠-٣٠ دقيقة. ومتحتاجش أدوات كتير. مسمار البرغي واحد، وعلبة لاستقبال الزيت القديم. خد ودان عن ميكانيكي وشاهد مرة أو اتنين وبعدين افعلها بنفسك.', styles), story=story)
    add(*S('تاني حاجة مهمة جداً — الإطارات. الإطارات هي نقطة التواصل الوحيدة بينك وبين الطريق. إطار باظ أو إطار هواؤه ناقص = خطر حقيقي على حياتك. وده مش بس موضوع فلوس — موضوع أمان.', styles), story=story)
    add(*M('للـ Z250، الإطار الأمامي عادةً ١١٠/٧٠-١٧ أو مشابه، والخلفي ١٤٠/٧٠-١٧. الضغط الصح للأمامي تقريباً ٢ بار ونص، والخلفي ٢.٨ لـ ٣ بار في الشغل بحمولة. قيس الضغط أسبوعياً على الأقل. ده مجاني ومحتاج ٥ دقايق فقط.', styles), story=story)
    add(*S('وإطار خد باله منه أكتر — الخلفي. لأن عليه الحمل والموتور والطاقة. الخلفي ممكن يدوم ٨٠٠٠-١٢٠٠٠ كيلو في الشغل الشديد. الأمامي ممكن يدوم ضعف ده. لما تلاقي العلامات جوة الكاوتش على الجانبين وصلت للسطح، غيّر فوراً. متستناش.', styles), story=story)
    add(*M('تالت حاجة — الفرامل. فرامل مش شغالة كويس في القاهرة ده كارثة. لأن إنت في الزحمة بتفرمل كل ١٠ ثواني تقريباً. تحقق من سُمك الـ Brake Pads شهرياً. لو السُمك أقل من ٢ ملم، غيّرهم فوراً. ومش غالية — الـ Brake Pads للـ Z250 بين ٨٠-١٥٠ جنيه على حسب النوع.', styles), story=story)
    add(*S('ورابع حاجة — السلسلة والتروس. السلسلة محتاجة تبقى نضيفة ومزيتة. كل ٥٠٠-٧٠٠ كيلو نضفها بـ kerosene أو Degreaser وبعدين زيتها بـ Chain Lube. ده بيطول عمرها بشكل كبير. سلسلة جديدة بتكلف ٤٠٠-٨٠٠ جنيه — إوفر بالزيت والتنظيف.', styles), story=story)
    add(*M('وخامس حاجة — البطارية. موتور مش بيشتغل من البطارية ده ضغط نفسي وضياع وقت. تحقق من مستوى المياه في البطارية كل شهر. وفي الشتا خصوصاً، لو موتورك بيقف كتير، شحن البطارية يمكن يحل المشكلة قبل ما تضطر تشتري بطارية جديدة بـ ٤٠٠-٦٠٠ جنيه.', styles), story=story)
    add(*S('وعندي نصيحة ذهبية في موضوع الصيانة. عمل علاقة كويسة مع ميكانيكي واحد قريب منك وبتثق فيه. مش بتجيله كل مرة مشكلة جديدة — بتيجيله بانتظام للصيانة الوقائية. الميكانيكي الكويس اللي عارفك وعارف موتورك هيوفرلك فلوس أكتر بكتير من اللي هيصلحلك كل حاجة بعد ما تبوظ.', styles), story=story)
    add(*M('وعندي جدول تقريبي للمصاريف السنوية للصيانة لو اتعملت صح: زيت + فلتر كل ٢ شهر = ٦ مرات × ٥٠٠ جنيه = ٣٠٠٠ جنيه سنوياً. إطار خلفي مرة = ٦٠٠-٩٠٠ جنيه. فرامل مرتين = ٣٠٠-٤٠٠ جنيه. سلسلة وتروس مرة = ٨٠٠-١٢٠٠ جنيه. باقي حاجات صغيرة = ٥٠٠ جنيه. مجموع: تقريباً ٦٠٠٠-٧٠٠٠ جنيه سنوياً.', styles), story=story)
    add(*S('و٦٠٠٠-٧٠٠٠ جنيه سنوياً يعني تقريباً ٥٠٠-٦٠٠ جنيه شهرياً. ده مبلغ يمكن تحسبه في تكلفة التشغيل الشهرية بتاعتك. وبدل ما يكون surprise إنفاق كبير، هيبقى متوقع ومتحسب.', styles), story=story)
    add(Spacer(1, 3*mm), story=story)
    add(SEC('— سيكولوجيا التوصيل: الزباين والدايري —', styles), story=story)
    add(SFX('صوت تلفون بيرن — صوت ناس في الشارع — تأبطة موتور — بوق', styles), story=story)

    add(*M('طب، نيجي لجزء مهم تاني — سيكولوجيا التوصيل. إزاي تتعامل مع الزبون، وإزاي تتعامل مع الطريق بطريقة تزود دخلك وتحافظ على صحتك النفسية.', styles), story=story)
    add(*S('ده موضوع إنت ما بتلاقيش عنه دورات أونلاين كتير! بس هو من أهم المهارات في الشغل. لأن موصل تعبان نفسياً بيعمل غلطات أكتر وبياخد تيبس أقل وبيتأخر أكتر.', styles), story=story)
    add(*M('أول مبدأ في التعامل مع الزباين — "الزبون مش عدوك". ده مبدأ بسيط بس كتير ناس بتنساه لما الزبون بيعمل تصرف ما يعجبكش. الزبون ده مصدر دخلك المباشر. وفي الوقت نفسه، إنت مش عبده. في وسط بين الاثنين.', styles), story=story)
    add(*S('إيه اللي بيحصل فعلاً؟ الزبون طلب أكل وهو جعان. الجوع بيخلي الناس أقل صبراً. لما تيجي متأخر، هو مش بيكرهك — هو جعان وضايق. فهمك للنقطة دي بيغير طريقة تعاملك بالكامل.', styles), story=story)
    add(*M('وعندي تيكنيك بسيط اتعلمته في التعامل مع الزبون المتضايق. لما توصل وهو واضح إنه مش مبسوط — ابدأ إنت بالاعتراف. قول "معلش على التأخير، في زحمة شديدة النهارده". كلمتين دول بيغيروا الجو تماماً في ٨٠٪ من الحالات.', styles), story=story)
    add(*S('ليه بيشتغل ده؟ لأن الزبون كان محتاج حد يعترف. هو مش محتاج تبرير أو قصة كاملة. هو محتاج تحس إنك مدرك إن في مشكلة وإنك مش فاهمه. الاعتراف البسيط بيخفف التوتر.', styles), story=story)
    add(*M('وموضوع التيبس — التيبس مش صدقة وإنت مش شحاذ بتطلبه. التيبس هو تعبير من الزبون عن رضاه. الطريقة الوحيدة إنك تزود التيبس هي إنك تقدم خدمة أحسن. مش إنك تطلبه أو تبدو مظلوم.', styles), story=story)
    add(*S('وإيه اللي بيخلي الزبون يدي تيبس؟ سرعة التسليم، الإطارة الكويسة في الأكل، الابتسامة، وأحياناً حاجة صغيرة زي "اتفضل، الأكل لسه سخن" بدل "اتفضل" بس.', styles), story=story)
    add(*M('واحد من أهم الحاجات هو "إدارة التوقعات". إذا الأوردر هياخد وقت، بلّغ الزبون مبكر. أرسله رسالة عبر التطبيق إن في تأخير بسيط. ده أحسن بكتير من إنه يكون مستنيك وإنت متأخر من غير إشعار.', styles), story=story)
    add(*S('وموضوع الطريق في القاهرة — الدايري تحديداً. الدائري ده حياة مختلفة. بيختلف عن شوارع المناطق بشكل كامل. وعندي نصايح من الشغل الفعلي.', styles), story=story)
    add(*M('يلا، إحنا بنستنى!', styles), story=story)
    add(*S('أول حاجة — الدائري في أوقات معينة هو أسرع طريق وفي أوقات تانية هو أبطأ حاجة تعملها. الساعة ٨-١٠ الصبح والساعة ٤-٧ مسا — الدائري مزدحم بشكل جنوني. في الأوقات دي، إذا الأوردر قريب، فضّل الشوارع الداخلية حتى لو بدت أبعد.', styles), story=story)
    add(*M('تاني حاجة — المعرفة الجغرافية هي أغلى أصل عندك. الموصل اللي عارف القاهرة كويس يعمل أوردرات أكتر في نفس الوقت. دايماً إنت بتتعلم الطرق من الشغل — لكن حاول تتعلم أسرع. بعد كل شيفت، افتح الخريطة وشوف الطرق اللي مشيت فيها وفكر في البدائل.', styles), story=story)
    add(*S('تالت حاجة — الأمان. وده مش كلام بيقوله حد عشان يبدو مسؤول. ده كلام عملي. موصل اتحادثة أو اتجرح، هو خسر فلوس طبية وخسر يوم شغل أو أكتر. الوقت اللي بتوفره من جري وخطورة مش بيساوي التكلفة اللي ممكن تتعب منها.', styles), story=story)
    add(*M('والحلمة هنا هي الـ Consistency. مش الـ Speed. الموصل اللي بيوصل ٣٠ أوردر في اليوم بانتظام لمدة ٣ سنين هيكسب أكتر بكتير من الموصل اللي بيوصل ٤٠ أوردر في يوم وبعدين يتعطل أسبوع بسبب حادثة.', styles), story=story)
    add(*S('ومع الوقت، هتلاقي نفسك عندك مناطق "الذهب" — مناطق فيها أوردرات كتير وتيبس كويسة وزحمة أقل. في القاهرة، المناطق زي المهندسين والزمالك والمعادي والتجمع فيها زباين بيدوا تيبس كويس. المناطق الجديدة والمركبات كمان كويسة. والأوردرات دي محتاج تتعلم توقيتها.', styles), story=story)
    add(*M('وموضوع المنافسة مع الموصلين التانيين — مش عدوك يا صاحبي. هو زميلك. لو اتعطلت في الطريق، هو اللي ممكن يساعدك. لو عندك سؤال عن منطقة ما، هو اللي يعرف. الشغل في القاهرة كبير بما يكفي للكل.', styles), story=story)
    add(SFX('موسيقى ترانزيشن — باس هيفي تراب', styles), story=story)
    add(PageBreak(), story=story)

    # ══════════════════════════════════════════
