    add(ACT('═══ الفصل الثالث ═══', styles), story=story)
    add(ACT('الخطة المالية: الجير مقابل الواقع', styles), story=story)
    add(T('[ الوقت: 01:15 — 01:45 ]', styles), story=story)
    add(HR(), story=story)
    add(SFX('صوت حاسبة — عملات معدنية — ترابي إنسترومنتال هادي', styles), story=story)
    add(Spacer(1, 4*mm), story=story)

    add(SEC('— كم أوردر يساوي ساوند كارد وميكروفون؟ —', styles), story=story)

    add(*M('طب! الجزء اللي بيحبه كل واحد عنده حلم بالموسيقى بس مش عارف يحسب — الخطة المالية الحقيقية. إحنا هنتكلم بأرقام حقيقية من الشارع. مش أرقام كتب نظريات.', styles), story=story)
    add(*S('وأنا بفضل الكلام بالأرقام لأن الأرقام مش بتكذب. لما تعرف بالظبط إنت محتاج كام أوردر عشان تشتري حاجة معينة، بيبقى عندك هدف حقيقي وملموس. مش بس "عايز أجمع فلوس وأعمل استوديو".', styles), story=story)
    add(*M('كويس. نبدأ بالأرقام الأساسية. موصل طلبات في القاهرة في المتوسط بيكسب بين ٨٠٠-١٢٠٠ جنيه يومياً في اليوم الكويس. في يوم عادي ممكن ٦٠٠-٨٠٠. ونحسب على أساس متوسط ٨٠٠ جنيه يومياً لأن ده حد وسط عملي.', styles), story=story)
    add(*S('٨٠٠ جنيه يومياً × ٢٦ يوم شغل في الشهر (مع راحة يومين أسبوعياً) = ٢٠٨٠٠ جنيه شهرياً إجمالي. بس ده إجمالي مش صافي. نطرح التكاليف.', styles), story=story)
    add(*M('تكاليف شهرية تقريبية: بنزين ٢٠٠٠-٢٥٠٠ جنيه، صيانة دورية ٥٠٠-٦٠٠ جنيه، تأمين موتور وتراخيص ٢٠٠ جنيه (حسب الشهر)، أكل وشرب وإنت في الشغل ٦٠٠ جنيه. مجموع تكاليف تقريباً: ٣٣٠٠-٣٩٠٠ جنيه شهرياً.', styles), story=story)
    add(*S('يعني صافي الربح الشهري: ٢٠٨٠٠ - ٣٩٠٠ = ١٦٩٠٠ جنيه تقريباً. ده الصافي قبل أي مصاريف شخصية أو مساهمة في البيت.', styles), story=story)
    add(*M('طب، لو فرضنا إن مصاريفك الشخصية والبيت بتاخد ١٠٠٠٠ جنيه شهرياً، يفضلك ٦٩٠٠ جنيه ممكن تحتها كل شهر للاستثمار في الاستوديو.', styles), story=story)
    add(*S('وده رقم كويس جداً لو اتعاملت معاه بجد. هنحسب دلوقتي. Focusrite Scarlett Solo (الجيل التالت) — ده أشهر ساوند كارد للبداية في مصر — سعره تقريباً ٣٥٠٠-٤٠٠٠ جنيه في السوق المصري أونلاين أو من المستورد.', styles), story=story)
    add(*M('يعني بـ الأرقام اللي قلناها، الـ Focusrite = نص الزيادة الشهرية. بمعنى آخر، بعد شهر ونص من الادخار من الزيادة، عندك ساوند كارد كويس. مش قصة.', styles), story=story)
    add(*S('والميكروفون — Audio Technica AT2020 الـ Condenser Mic — ده أشهر ميك بداية في مصر ومناسب لتسجيل البوكال والـ Rap. سعره تقريباً ٤٥٠٠-٥٥٠٠ جنيه في مصر.', styles), story=story)
    add(*M('يعني شهر تاني من الادخار وعندك الميك. شهرين من الادخار المنظم وعندك الـ Interface + الميك. ده مش كلام فاضي — ده خطة حقيقية.', styles), story=story)
    add(*S('بس هنا الفخ اللي كتير بيقع فيه. بيجمعوا الفلوس للاستوديو وبعدين يشتروا آيفون جديد أو يسافروا نزهة أو يشتروا ملابس. وبكره بيقولوا "مش لاقي فلوس للاستوديو".', styles), story=story)
    add(*M('وده بيجيبنا للموضوع الأهم في الفصل ده — الـ Delayed Gratification. إنك تقدر تقاوم الإغراء الفوري عشان تحقق هدف أكبر. وده مهارة — مش شخصية. بتتعلمها.', styles), story=story)
    add(Spacer(1, 3*mm), story=story)
    add(SEC('— استوديو في أوضة صغيرة: ممكن؟ نعم! —', styles), story=story)
    add(SFX('صوت فيسات ترابية — معالجة صوتية — صدى جدران', styles), story=story)

    add(*S('طب دلوقتي، عندك الجير — الساوند كارد والميك. فين تسجل؟ في أوضتك الصغيرة في القاهرة. وده ممكن تماماً لو عرفت تعمل كده.', styles), story=story)
    add(*M('أكبر مشكلة في التسجيل في أوضة عادية هي الـ Acoustics السيئة — الصدى والانعكاس. الصوت بيرتد من الحيطان ويدخل في التسجيل ويعمل echo وreverberation مش عايزينها.', styles), story=story)
    add(*S('الحل المحترف هو acoustic treatment — فوم مخصوص وبانلات بتشرب الصوت. بس ده غالي. الحل البلدي الشغال؟ استخدم ما عندك.', styles), story=story)
    add(*M('أول حاجة — إيجاد "الزاوية الميتة" في أوضتك. الزاوية اللي فيها أقل صدى. عادةً بتكون الزاوية اللي فيها دواليب ملابس أو رف كتب أو فرشة سميكة. الحاجات دي بتشرب الصوت طبيعياً.', styles), story=story)
    add(*S('تاني حاجة — الـ DIY Vocal Booth. إيه ده بالعربي؟ بتاخد علاقة هدوم وبتلفّها بكل الحوايج الصوفية اللي عندك — كوفرتات، حوايج سميكة، تيشرتات كتير — وبتعمل "خيمة" حوالين الميك وحوالينك. ده بيقلل الصدى ٥٠-٧٠٪.', styles), story=story)
    add(*M('وأنا شايف الفيديوهات دي على يوتيوب وبتضحك. بس الصوت بيطلع مختلف فعلاً! النهارده في أوضة بدون معالجة الصوت بيكون معاه echo واضح. في الـ blanket booth الصوت بيكون أنضف بشكل ملحوظ.', styles), story=story)
    add(*S('والـ Closet Recording Studio — ده option تاني. لو عندك دولاب كبير فيه حوايج كتير، التسجيل جواه بيكون مذهل. الحوايج عازل صوت ممتاز. كتير من أشهر الـ YouTube channels بدأوا بالتسجيل في الدولاب.', styles), story=story)
    add(*M('طب، الجهاز نفسه — اللاب توب. محتاج اللاب توب عشان تشتغل عليه الـ DAW بتاعتك. الـ DAW هو البرنامج اللي بتعمل فيه الموسيقى. للبداية، Audacity مجاني تماماً وبيشتغل على أي جهاز. ولو عايز أحسن — GarageBand مجاني على Mac، وFL Studio بيكون حواليه ٢٠٠ دولار بس في بعض الأحيان بتلاقي alternatives أقل.', styles), story=story)
    add(*S('ولو الموضوع موسيقى ترابي أو بيتميكينج — FL Studio هو الـ industry standard للتراب والهيب هوب. بس ما تشتريش من أول يوم. ابدأ بالـ Free Trial وتعلم البرنامج الأول. لما تحس إنك ضيق فعلاً من الـ trial limitations، يبقى إنت جاهز للاستثمار.', styles), story=story)
    add(*M('وسماعات المونيتور — محتاجها؟ للبداية، سماعاتك العادية أو سماعة الموبايل ممكن تستخدمها. مش مثالي بس شغال. لما تبدأ تعمل موسيقى وتحس إن الـ mix بتاعتك بيطلع different على سماعات تانية، يبقى وقت تستثمر في Monitor Speakers.', styles), story=story)
    add(*S('Yamaha HS5 أو HS7 من أحسن Monitor Speakers للبداية. بيتكلفوا ٥٠٠٠-٧٠٠٠ جنيه الحبة في مصر. بس دي مش أول حاجة تشتريها — خليها الـ Step 3 أو 4 في الخطة بتاعتك.', styles), story=story)
    add(*M('طب، نعمل جدول زمني للخطة المالية الكاملة. شهر ١-٢: ادخار + تعلم DAW مجاني. شهر ٣: شراء Focusrite Scarlett Solo. شهر ٤-٥: تعلم وتسجيل بالـ Interface. شهر ٦: شراء AT2020 Mic. شهر ٧-١٢: إنتاج وتطوير المهارات. سنة ٢: إضافة Monitors.', styles), story=story)
    add(*S('وفي كل الفترة دي، إنت مش بس بتجمع جير — إنت بتتعلم. التعلم مجاني على يوتيوب. في قنوات زي In The Mix وProducer Hive وMasterclass on a Budget تعلمك كل حاجة من التسجيل للـ Mixing للـ Mastering.', styles), story=story)
    add(Spacer(1, 3*mm), story=story)
    add(SEC('— الادخار مقابل الإنفاق: الحقيقة اللي محدش بيقولهالك —', styles), story=story)
    add(SFX('صوت موبايل جديد بيفتح — بعدين صوت قيثارة — ترابي', styles), story=story)

    add(*M('طب، الموضوع اللي هيحكي على الجدار الحقيقي. ليه ما تشتريش آيفون جديد وبدل كده تشتري جير موسيقى؟ وأنا هجاوب على الموضوع ده بدون ما أقول لك "الموسيقى أهم من الموبايل" لأن ده مش تفكير تحليلي.', styles), story=story)
    add(*S('السؤال الصح مش "إيه اللي أهم؟" السؤال الصح هو "إيه اللي يقربك من هدفك؟". لو هدفك إنك تبقى موسيقي وتعيش من الموسيقى — يبقى آيفون جديد لا يقربك من الهدف ده ولا يبعدك منه بشكل حقيقي.', styles), story=story)
    add(*M('بس الساوند كارد والميك — دول بيحولوا حلمك من فكرة في دماغك لحاجة حقيقية موجودة. وده فرق ضخم من الناحية النفسية وكمان العملية.', styles), story=story)
    add(*S('وعندي سؤال بسألوه لنفسي كل ما باجه أشتري حاجة: "هل ده هيساعدني أعمل شغل أحسن؟" لو الإجابة لأ، إنت مش شايل أي فلوس — إنت شايل حاجة هتفضل تنتهي. لو الإجابة أه، حتى لو الحاجة غالية، هي استثمار.', styles), story=story)
    add(*M('طبعاً في حدود! مش معناه إنك ما تعيشش وما تاكلش كويس عشان تجمع جير. الأكل الكويس والراحة مهمين للإبداع. بس الـ iPhone 16 Pro Max بدل الـ iPhone 12 اللي شغال — ده مش استثمار، ده خسارة.', styles), story=story)
    add(*S('وموضوع بطاقات التقسيط والقروض — ده موضوع حساس جداً. في مصر دلوقتي في إمكانية تشتري جير بالتقسيط. وأنا رأيي إن التقسيط للجير الموسيقي ممكن يكون كويس لو الشروط كويسة — بس بشرط واحد: إنك تكون عندك income ثابت يغطي القسط من غير ما يضغط عليك.', styles), story=story)
    add(*M('لو الأوردرات بتكسب ١٦٠٠٠ جنيه صافي شهرياً وقسط الجير ٦٠٠ جنيه شهرياً، ده ٣.٧٪ من دخلك. ده acceptable. لو القسط ٣٠٠٠ جنيه، ده ١٨٪ من دخلك وده ثقيل شوية.', styles), story=story)
    add(*S('والنقطة الأهم — لا تشتري بالتقسيط حاجة ما تعرفش تستخدمها كويس. اشتري ساوند كارد بس لو عرفت تشغّله. اشتري ميك بس لو عندك DAW وعارف تسجل. الجير بدون المعرفة هو شراء وهم.', styles), story=story)
    add(*M('وعندي مبدأ ذهبي في الموضوع ده: "المهارة قبل الجير". المهارة في استخدام FL Studio على اللاب توب اللي عندك أهم من أفضل استوديو بدون مهارة. في ناس عملوا أغاني هتكسر الدنيا على GarageBand على موبايل. وفي ناس صرفوا مئات الآلاف على استوديوهات وما طلع منهم حاجة تتسمع.', styles), story=story)
    add(*S('الفرق مش في الجير — في المهارة والصبر والتكرار. المهارة بتيجي من التكرار. التكرار محتاج وقت. والوقت ده ممكن تستخدمه كويس أو بالراحة. الاختيار اختيارك.', styles), story=story)
    add(*M('وهنا بيجي الربط الجميل بين الفصل الأول والتالت. نفس المهارة اللي ذاكرت بيها في الثانوية — التنظيم والـ Consistency والصبر — هي نفس المهارة اللي محتاجها في بناء استوديو ومسيرة موسيقية. الدنيا مش بتتغير قوانينها، بس الـ Context بيتغير.', styles), story=story)
    add(SFX('موسيقى ترانزيشن صاعدة — ترابي إيموشنال', styles), story=story)
    add(PageBreak(), story=story)

    # ══════════════════════════════════════════
    # ACT 4
