    add(SEC('— التراب والمهرجانات: الكروسوفر اللي بيغير القواعد —', styles), story=story)

    add(*M('آخر فصل يا ناس! وده الفصل اللي أنا شخصياً بحبه أكتر لأنه بيتكلم عن المستقبل. عن الفيجن. عن ييت ويونغ جيزة وكل اللي بينهم وبيننا.', styles), story=story)
    add(*S('ييت — جيفري لامار ويليامز. واحد من أغرب وأجرأ الشخصيات في الموسيقى الأمريكية. مش بس موسيقاه غريبة — أسلوبه في التعامل مع الـ Industry غريب. وده اللي بيخليه مثير جداً للدراسة لأي حد عايز يعمل حاجة مختلفة.', styles), story=story)
    add(*M('ييت مش بيغني عن حاجات عادية. ييت بيغني عن الـ Pain والـ Isolation والـ Opulence في نفس الوقت. عن الحياة المادية والفراغ الداخلي. وده كلام الناس قالوا عنه إنه "مش كلام" — لكنه وصل لملايين.', styles), story=story)
    add(*S('والدرس من ييت مش إنك تقلده. الدرس هو إنك تكون authentic. إنك تقول اللي إنت حاسسه بالفعل. مش اللي تفتكر إن الناس عايزة تسمعه. الأوثنتيكيتي هي المصدر الحقيقي لأي موسيقى بتأثر في الناس.', styles), story=story)
    add(*M('والمهرجانات — ده أكتر genre اتخلق في مصر وأكتر حاجة جدل حواليها. الناس كانت بتقول "ده مش موسيقى". والنهارده المهرجانات بتملأ الحفلات وعندها ملايين المشاهدات وصنعت نجوم من الصفر من أحياء كانت ما حدش يسمع عنها.', styles), story=story)
    add(*S('المهرجانات هي التراب المصري. نفس الروح — موسيقى من الشارع، من الألم، من الأمل، من الحياة اليومية للناس العادية. بس بأدوات وإيقاعات مختلفة وكلام بالعامية المصرية. وده بيخليها powerful جداً لأنها بتوصل لناس بتحس بكل كلمة.', styles), story=story)
    add(*M('والكروسوفر بين التراب الأمريكي والمهرجانات المصرية — ده مش مجرد تجربة موسيقية. ده فرصة حقيقية لواحد عارف الاتنين يعمل حاجة مختلفة. إنك تاخد الـ Dark Trap Production — الهيفي باس، الـ 808s، الـ Hi-Hats الكتير — وتحطه تحت كلام عربي مصري حقيقي.', styles), story=story)
    add(*S('ودي مش فكرة جديدة خالص — فيه ناس اشتغلوا عليها. بس النقطة المهمة هي إن الساحة لسه كبيرة ومش متشبعة. والواحد اللي عنده صوت أوثنتيك وعنده story حقيقية وعنده مهارة تقنية — عنده فرصة حقيقية.', styles), story=story)
    add(Spacer(1, 3*mm), story=story)
    add(SEC('— من المكنة لكلمات تبقى حقيقية —', styles), story=story)
    add(SFX('موتوسيكل بيمشي في الشارع — ضجيج المدينة — بعدين بيانو واحد', styles), story=story)

    add(*M('طب، الجزء المهم. إزاي تستخدم تجربتك في المكنة والشوارع عشان تكتب كلمات حقيقية وحاسسة؟', styles), story=story)
    add(*S('وأنا هقولك سر: التجربة اللي بيتمنى إنها ما كانتش، دي هي أقوى مصدر للإبداع عندك. الليالي اللي كنت فيها مصحصح في الدايري والجو برد والجيب فاضي والأوردرات خلصت — دي كلمات جاهزة. إنت مش محتاج تتخيلها.', styles), story=story)
    add(*M('الـ Authenticity في الموسيقى بتيجي من اللي عشته. ييت بيغني عن حياته الحقيقية. الأحياء بتغني عن حياتهم الحقيقية. أنت كمان، لو غنيت عن الدايري والأوردر والبرد والأمل والتعب — ده real. وده اللي الناس بتحس بيه.', styles), story=story)
    add(*S('وهنا مبدأ مهم: "الكلمة من المعاشة مش من الخيال". لما بتكتب كلمات، مش محتاج تبقى شاعر فصيح. محتاج تكون صادق. كلمة واحدة صادقة بتعدي ألف كلمة متزوقة فاضية.', styles), story=story)
    add(*M('طيب، إزاي تبدأ تكتب؟ التيكنيك الأول — الـ Freestyle Journal. كل يوم بعد الشيفت، وإنت تعبان وعارف إن محدش شايفك — اكتب ٥ دقايق. اكتب بالكلمات اللي في دماغك. من غير ما تفكر في أنها كويسة أو لأ. بس اكتب.', styles), story=story)
    add(*S('التيكنيك ده بيعمل حاجتين: أولاً بيطلع اللي جوا برا. وتانياً بيراكم مادة خام هتلاقي فيها جواهر بعدين. كتير من أكبر الهيتس اتعملوا من فكرة كانت أصلاً في دفتر صغير.', styles), story=story)
    add(*M('والتيكنيك التاني — الـ Voice Memos. موبايلك معاك على المكنة. أي فكرة أو جملة بتيجي في دماغك — سجلها فوراً. ماتصدقش الناس اللي بيقولوا "هافتكرها". النسيان سريع جداً، خصوصاً لما إنت في موضوع التعب والتركيز على الطريق.', styles), story=story)
    add(*S('والتيكنيك التالت — الـ Story Mining. خد حدث واحد من حياتك على المكنة وحوله لقصة. مثلاً: أوردر تأخرت فيه وكان في زحمة والزبون زعل. اكتب القصة دي بالتفاصيل. الساعة، الجو، الإحساس، رد فعل الزبون، إحساسك إنت. القصة دي ممكن تبقى أغنية.', styles), story=story)
    add(*M('وفي الكتابة الترابية والمهرجانات، في عناصر معينة بتخلي الكلمة قوية: الصورة الحسية — مش قول "كنت تعبان" قول "الشتا كان على وشي والموتور بتبرد زي قلبي". الصورة دي بتعمل فيلم في دماغ المستمع.', styles), story=story)
    add(*S('والـ Contrast — الفرق بين التعب والحلم، بين الواقع والطموح، بين الشارع والنجومية. ده الـ tension اللي بيخلي الموسيقى مثيرة عاطفياً. ييت عنده ده في كل أغنية تقريباً — الـ Wealth والـ Pain في نفس الـ verse.', styles), story=story)
    add(*M('وموضوع التوصيل والموسيقى — فيه رابط مش واضح للناس. في التوصيل بتشتغل لوحدك كتير. وقت الشغل الوحيد ده هو وقت تفكير. الناس اللي في الأوفيس لازم يتكلموا في meetings — إنت في التوصيل عندك ساعات من التفكير الحر. استخدمها.', styles), story=story)
    add(*S('كتير من أفضل الأغاني اتكتبت وإنت ماشي. الإيقاع الجسدي للمشي — أو ركوب الموتور — بيحفز الإبداع. والبيئة الصوتية للشارع — الأبواق والأصوات والضوضاء — دي بتكون في دماغك ومع الوقت بتلاقي نفسك بتحول الضوضاء دي لإيقاعات.', styles), story=story)
    add(Spacer(1, 3*mm), story=story)
    add(SEC('— الموتيفيشن النهائي: من توصيل الأكل لتوصيل الهيتس —', styles), story=story)
